        NodeList metadataNodes = dataPayload.getElementsByTagNameNS("*", "Metadata");
        if (metadataNodes.getLength() > 0) {
            Element metadataElement = (Element) metadataNodes.item(0);
            Map<String, String> metadata = parseMetadata(metadataElement);
            request.setMetadata(metadata);
        }
        
        return request;
